import numpy as np

class MeasurementPipeline:
    def __init__(self, n_qubits):
        self.n_qubits = n_qubits
        self.dim = 2 ** n_qubits
        self.confusion_matrix = None

    def calibrate(self, noise_model, n_shots=10000):
        # Build confusion matrix from noise model
        self.confusion_matrix = np.zeros((self.dim, self.dim))

        for prep_idx in range(self.dim):
            prep_state = format(prep_idx, f'0{self.n_qubits}b')

            for meas_idx in range(self.dim):
                meas_state = format(meas_idx, f'0{self.n_qubits}b')

                # Probability of this outcome
                prob = 1.0
                for q in range(self.n_qubits):
                    prep_bit = prep_state[q]
                    meas_bit = meas_state[q]

                    if prep_bit == '0' and meas_bit == '0':
                        prob *= (1 - noise_model[q]['p0_to_1'])
                    elif prep_bit == '0' and meas_bit == '1':
                        prob *= noise_model[q]['p0_to_1']
                    elif prep_bit == '1' and meas_bit == '0':
                        prob *= noise_model[q]['p1_to_0']
                    else:  # 1 -> 1
                        prob *= (1 - noise_model[q]['p1_to_0'])

                self.confusion_matrix[meas_idx, prep_idx] = prob

    def mitigate_counts(self, counts):
        total = sum(counts.values())

        # Convert to probabilities
        probs = np.zeros(self.dim)
        for state, count in counts.items():
            idx = int(state, 2)
            probs[idx] = count / total

        # Mitigate
        inv_M = np.linalg.pinv(self.confusion_matrix)
        mitigated = inv_M @ probs
        mitigated = np.clip(mitigated, 0, None)
        mitigated /= np.sum(mitigated)

        # Convert back to counts
        result = {}
        for i in range(self.dim):
            if mitigated[i] > 1e-6:
                state = format(i, f'0{self.n_qubits}b')
                result[state] = round(mitigated[i] * total)

        return result

# Test
np.random.seed(42)
pipeline = MeasurementPipeline(n_qubits=2)

noise_model = {
    0: {'p0_to_1': 0.02, 'p1_to_0': 0.05},
    1: {'p0_to_1': 0.03, 'p1_to_0': 0.06}
}

pipeline.calibrate(noise_model)

print("Confusion Matrix:")
print(pipeline.confusion_matrix)

counts = {'00': 4500, '01': 200, '10': 150, '11': 5150}
mitigated = pipeline.mitigate_counts(counts)

print(f"\nNoisy counts: {counts}")
print(f"Mitigated: {mitigated}")
